        [Parameter(Mandatory)] $Filter
    )
    foreach ($k in $Filter.Keys) {
        if (-not $Combo.Contains($k)) { return $false }
        if ($Combo[$k] -ne $Filter[$k]) { return $false }
    }
    return $true
}

