function script:Get-ActJsonBlock {
    param([string]$Haystack, [string]$StartTag, [string]$EndTag)
    $m = [regex]::Match($Haystack, [regex]::Escape($StartTag) + '(?<b>.*?)' + [regex]::Escape($EndTag), 'Singleline')
    if (-not $m.Success) { return $null }
    # Act prefixes every body line with "[workflow/job]   | ". Strip that prefix
    # and concatenate lines so the JSON body survives reassembly.
    $lines = $m.Groups['b'].Value -split "`n"
    $clean = foreach ($l in $lines) {
        $l2 = $l -replace '^\s*\[[^\]]*\]\s*\|\s?', ''
        $l2
    }
    return ($clean -join "`n").Trim()
}

